machine_start_gcode:
M83
M140 S{first_layer_bed_temperature[initial_tool]} ; Bett vorheizen
M104 S{first_layer_temperature[initial_tool]} T{initial_tool} ; Hotend vorheizen
G28 ; Homing X Y Z
BED_MESH_PROFILE LOAD=default ; gespeichertes Mesh laden
M190 S{first_layer_bed_temperature[initial_tool]} ; warten bis Bett warm
M109 S{first_layer_temperature[initial_tool]} T{initial_tool} ; warten bis Hotend warm
{if initial_tool == 0}SELECT_PH1{endif}
{if initial_tool == 1}SELECT_PH2{endif}
{if initial_tool == 2}SELECT_PH3{endif}
{if initial_tool == 3}SELECT_PH4{endif}
{if initial_tool == 4}SELECT_PH5{endif}
G92 E0 ; Extruder-Position resetten
G1 Z5 F600 ; Z anheben
